import pandas as pd
import numpy as np

# Risk-based authentication scoring system
def compute_risk_score(new_device, new_country, unusual_hour, failed_attempts, velocity_high):
    risk_score = 0
    if new_device:
        risk_score += 30
    if new_country:
        risk_score += 40
    if unusual_hour:
        risk_score += 15
    if failed_attempts > 0:
        risk_score += failed_attempts * 25
    if velocity_high:
        risk_score += 35
    return risk_score

def classify_risk(score):
    if score < 30:
        return 'low', 'allow'
    elif score < 60:
        return 'medium', 'require_mfa'
    else:
        return 'high', 'block_alert'

# Simulate 8 login attempts
login_events = [
    {'user': 'user_001', 'new_device': False, 'new_country': False, 'unusual_hour': False, 'failed_attempts': 0, 'velocity': 1},
    {'user': 'user_002', 'new_device': True, 'new_country': False, 'unusual_hour': False, 'failed_attempts': 0, 'velocity': 1},
    {'user': 'user_003', 'new_device': True, 'new_country': True, 'unusual_hour': True, 'failed_attempts': 2, 'velocity': 0},
    {'user': 'user_004', 'new_device': False, 'new_country': False, 'unusual_hour': True, 'failed_attempts': 1, 'velocity': 0},
    {'user': 'user_005', 'new_device': True, 'new_country': True, 'unusual_hour': False, 'failed_attempts': 0, 'velocity': 0},
    {'user': 'user_006', 'new_device': False, 'new_country': False, 'unusual_hour': False, 'failed_attempts': 0, 'velocity': 6},
    {'user': 'user_007', 'new_device': True, 'new_country': True, 'unusual_hour': True, 'failed_attempts': 3, 'velocity': 1},
    {'user': 'user_008', 'new_device': False, 'new_country': False, 'unusual_hour': False, 'failed_attempts': 0, 'velocity': 0}
]

results = []
for event in login_events:
    score = compute_risk_score(
        event['new_device'],
        event['new_country'],
        event['unusual_hour'],
        event['failed_attempts'],
        event['velocity'] > 5
    )
    risk_level, decision = classify_risk(score)
    results.append({
        'user': event['user'],
        'risk_score': score,
        'risk_level': risk_level,
        'decision': decision
    })

results_df = pd.DataFrame(results)
print(results_df.to_string(index=False))

