# Synthetic identity detection
def check_ssn_age(ssn, dob):
    """Check if SSN issue date is before DOB (red flag)"""
    ssn_issue_year = int(ssn[:3])  # Simplified: first 3 digits relate to year
    dob_year = int(dob[:4])
    return ssn_issue_year < dob_year  # Should be False (SSN issued after birth)

def check_address_validity(address):
    """Check if address appears in credit bureau (0=not found, 1=found)"""
    # Simulated: real implementation would query credit bureau API
    valid_addresses = {'123 Main St', '456 Oak Ave', '789 Elm St'}
    return 1 if address in valid_addresses else 0

def check_name_ssn_match(name, ssn):
    """Check if name matches SSN records (1=match, 0=mismatch)"""
    # Simulated
    ssn_names = {'John Smith': '123456789', 'Jane Doe': '987654321'}
    return 1 if name in ssn_names and ssn_names[name] == ssn else 0

def synthetic_identity_risk(name, ssn, dob, address):
    flags = 0
    if not check_ssn_age(ssn, dob):
        flags += 1  # SSN issued before DOB
    if not check_address_validity(address):
        flags += 1  # Address not in credit bureau
    if not check_name_ssn_match(name, ssn):
        flags += 1  # Name mismatch
    return flags

# Test 5 identity profiles
identities = [
    {'name': 'John Smith', 'ssn': '123456789', 'dob': '1985-05-15', 'address': '123 Main St'},
    {'name': 'Jane Doe', 'ssn': '987654321', 'dob': '1990-08-22', 'address': '456 Oak Ave'},
    {'name': 'Robert Brown', 'ssn': '555666777', 'dob': '1980-03-10', 'address': '999 Fake St'},
    {'name': 'Sarah Johnson', 'ssn': '111222333', 'dob': '1975-12-01', 'address': '123 Main St'},
    {'name': 'Michael Davis', 'ssn': '444555666', 'dob': '1988-07-25', 'address': '789 Elm St'}
]

for identity in identities:
    risk = synthetic_identity_risk(identity['name'], identity['ssn'], identity['dob'], identity['address'])
    print(f"{identity['name']}: synthetic_identity_flags={risk}")
